const input = $json.body ?? $json;
const requestedModel = (input.model ?? 'or-fast').toString();
const skillId = input.skillId == null ? null : input.skillId.toString();
const outputMode = ['text', 'email', 'ticket', 'json'].includes((input.outputMode ?? '').toString())
  ? input.outputMode.toString()
  : 'text';

const allowedModels = [
  'or-fast',
  'or-strong',
  'or-ultracheap',
  'or-cheap-gemma-2-9b',
  'or-cheap-mistral-7b',
  'or-cheap-phi-4',
  'or-cheap-qwen-2-5-7b',
  'or-fast-claude-3-5-haiku',
  'or-fast-qwen-3-32b',
  'or-fast-qwen-2-5-coder-32b',
  'or-best-gpt-4o',
  'or-best-mistral-large-2512',
  'or-best-deepseek-r1'
];

if (!allowedModels.includes(requestedModel)) {
  throw new Error(`Invalid model alias: ${requestedModel}`);
}

const incomingMessages = Array.isArray(input.messages)
  ? input.messages
      .map((msg) => ({
        role: (msg?.role ?? '').toString().trim(),
        content: (msg?.content ?? '').toString()
      }))
      .filter((msg) => ['system', 'user', 'assistant'].includes(msg.role) && msg.content.trim())
  : [];

let messages = incomingMessages;

if (!messages.length) {
  const text = (input.text ?? '').toString().trim();
  if (!text) {
    throw new Error('Missing required field: messages or text');
  }
  messages = [{ role: 'user', content: text }];
}

return [{
  json: {
    skillId,
    model: requestedModel,
    outputMode,
    body: {
      model: requestedModel,
      messages,
      max_tokens: 400
    }
  }
}];

const msg = $json.choices?.[0]?.message;
let content = msg?.content;

if (Array.isArray(content)) {
  const textParts = content
    .map((part) => {
      if (typeof part === 'string') return part;
      if (part && typeof part.text === 'string') return part.text;
      return '';
    })
    .filter(Boolean);
  content = textParts.join('\n').trim();
}

if (typeof content !== 'string' || !content.trim()) {
  const fallback = $json.choices?.[0]?.text;
  if (typeof fallback === 'string' && fallback.trim()) {
    content = fallback.trim();
  }
}

if (typeof content !== 'string' || !content.trim()) {
  throw new Error('LiteLLM returned an empty response content');
}

return [{ json: { content: content.trim() } }];
